--- a/packages/ui/src/engine/pixel-characters.ts
+++ b/packages/ui/src/engine/pixel-characters.ts
@@ 2389,6 +2389,69 @@
+// ─── Castle overview floor plan ─────────────────────────────────────
+
+interface Room {
+  id: string;
+  type: CharacterType;
+  x: number;
+  y: number;
+  w: number;
+  h: number;
+}
+
+function drawDoorway(ctx: CanvasRenderingContext2D, x: number, y: number, w: number, h: number, horizontal: boolean) {
+  ctx.save();
+  ctx.fillStyle = '#6b4c2b';
+  if (horizontal) {
+    // Draw horizontal doorway (door frame)
+    const doorWidth = w * 0.2;
+    const doorHeight = h * 0.15;
+    const dx = x + (w - doorWidth) / 2;
+    const dy = y;
+    ctx.fillRect(dx, dy, doorWidth, doorHeight);
+    ctx.strokeStyle = '#4a2f1a';
+    ctx.lineWidth = 2;
+    ctx.strokeRect(dx, dy, doorWidth, doorHeight);
+  } else {
+    // Draw vertical doorway (door frame)
+    const doorWidth = w * 0.15;
+    const doorHeight = h * 0.2;
+    const dx = x;
+    const dy = y + (h - doorHeight) / 2;
+    ctx.fillRect(dx, dy, doorWidth, doorHeight);
+    ctx.strokeStyle = '#4a2f1a';
+    ctx.lineWidth = 2;
+    ctx.strokeRect(dx, dy, doorWidth, doorHeight);
+  }
+  ctx.restore();
+}
+
+export function drawCastleOverview(ctx: CanvasRenderingContext2D, rooms: Room[], scale: number) {
+  // Determine bounds of all rooms
+  if (rooms.length === 0) return;
+  const margin = 10;
+  let minX = Math.min(...rooms.map(r => r.x));
+  let minY = Math.min(...rooms.map(r => r.y));
+  let maxX = Math.max(...rooms.map(r => r.x + r.w));
+  let maxY = Math.max(...rooms.map(r => r.y + r.h));
+
+  // Draw background
+  ctx.fillStyle = '#222222';
+  ctx.fillRect(0, 0, (maxX - minX + margin * 2) * scale, (maxY - minY + margin * 2) * scale);
+
+  // Draw rooms
+  for (const room of rooms) {
+    const rx = (room.x - minX + margin) * scale;
+    const ry = (room.y - minY + margin) * scale;
+    const rw = room.w * scale;
+    const rh = room.h * scale;
+    // Room background
+    ctx.fillStyle = '#444444';
+    ctx.fillRect(rx, ry, rw, rh);
+    // Room border
+    ctx.strokeStyle = '#888888';
+    ctx.lineWidth = 2;
+    ctx.strokeRect(rx, ry, rw, rh);
+    // Room label
+    ctx.fillStyle = '#cccccc';
+    ctx.font = `${Math.floor(scale * 0.4)}px sans-serif`;
+    ctx.textAlign = 'center';
+    ctx.textBaseline = 'middle';
+    ctx.fillText(room.type, rx + rw / 2, ry + rh / 2);
+  }
+
+  // Draw corridors and doorways between adjacent rooms
+  // Consider adjacency if rooms share an edge horizontally or vertically
+  for (let i = 0; i < rooms.length; i++) {
+    for (let j = i + 1; j < rooms.length; j++) {
+      const a = rooms[i];
+      const b = rooms[j];
+      // Check horizontal adjacency (rooms side by side)
+      const horizontalAdj = (a.y < b.y + b.h) && (a.y + a.h > b.y) &&
+                            (Math.abs(a.x + a.w - b.x) < 1e-6 || Math.abs(b.x + b.w - a.x) < 1e-6);
+      // Check vertical adjacency (rooms stacked)
+      const verticalAdj = (a.x < b.x + b.w) && (a.x + a.w > b.x) &&
+                          (Math.abs(a.y + a.h - b.y) < 1e-6 || Math.abs(b.y + b.h - a.y) < 1e-6);
+      if (horizontalAdj) {
+        // Draw corridor between a and b horizontally
+        const leftRoom = a.x < b.x ? a : b;
+        const rightRoom = a.x < b.x ? b : a;
+        const cx = (leftRoom.x + leftRoom.w) - minX + margin;
+        // Vertical overlap range
+        const topY = Math.max(leftRoom.y, rightRoom.y) - minY + margin;
+        const bottomY = Math.min(leftRoom.y + leftRoom.h, rightRoom.y + rightRoom.h) - minY + margin;
+        const cy = (topY + bottomY) / 2;
+        const corridorWidth = scale * 6;
+        const corridorHeight = scale * 10;
+        ctx.fillStyle = '#886644';
+        ctx.fillRect(cx * scale, (cy * scale) - corridorHeight / 2, corridorWidth, corridorHeight);
+        // Draw doorways on each room side
+        drawDoorway(ctx, cx * scale, (cy * scale) - corridorHeight / 2, corridorWidth, corridorHeight, false);
+      } else if (verticalAdj) {
+        // Draw corridor between a and b vertically
+        const topRoom = a.y < b.y ? a : b;
+        const bottomRoom = a.y < b.y ? b : a;
+        const cy = (topRoom.y + topRoom.h) - minY + margin;
+        // Horizontal overlap range
+        const leftX = Math.max(topRoom.x, bottomRoom.x) - minX + margin;
+        const rightX = Math.min(topRoom.x + topRoom.w, bottomRoom.x + bottomRoom.w) - minX + margin;
+        const cx = (leftX + rightX) / 2;
+        const corridorWidth = scale * 10;
+        const corridorHeight = scale * 6;
+        ctx.fillStyle = '#886644';
+        ctx.fillRect((cx * scale) - corridorWidth / 2, cy * scale, corridorWidth, corridorHeight);
+        // Draw doorways on each room side
+        drawDoorway(ctx, (cx * scale) - corridorWidth / 2, cy * scale, corridorWidth, corridorHeight, true);
+      }
+    }
+  }
+}
+
